            instructions = [instructions]
        names_labels = []
        for inst in instructions:
            if isinstance(inst, Instruction):
                name = inst.name
                label = getattr(inst, "label", inst.name)
                names_labels.append((name, label))
            elif isinstance(inst, str):
                names_labels.append((inst, inst))
